import React, { useState, useEffect } from "react";
import { io } from "socket.io-client";

const socket = io("http://localhost:3001");

export default function PrivateChat({ currentUser, friend }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");

  useEffect(() => {
    socket.emit("register user", currentUser.userId);

    socket.on("chat message", (data) => {
      if (data.senderId === friend.userId || data.senderId === currentUser.userId) {
        setMessages(prev => [...prev, data]);
      }
    });

    return () => socket.off("chat message");
  }, [friend, currentUser]);

  const sendMessage = () => {
    socket.emit("chat message", {
      senderId: currentUser.userId,
      receiverId: friend.userId,
      message: input
    });
    setInput("");
  };

  return (
    <div>
      <h4>Chat with {friend.userId}</h4>
      <div style={{ border: "1px solid #ccc", height: "200px", overflowY: "scroll" }}>
        {messages.map((msg, i) => (
          <div key={i}><b>{msg.senderId}:</b> {msg.message}</div>
        ))}
      </div>
      <input value={input} onChange={e => setInput(e.target.value)} />
      <button onClick={sendMessage}>Send</button>
    </div>
  );
}
